import numpy as np

class HookRegistry:
    def __init__(self):
        self.features = {}

    def hook(self, name: str):
        def _hook(output):
            self.features[name] = output.copy()
        return _hook

    def clear(self):
        self.features.clear()

class ConvBlock:
    def __init__(self, W: np.ndarray, b: np.ndarray, name: str = 'conv'):
        self.W = W
        self.b = b
        self.name = name
        self._hooks = []

    def register_hook(self, hook_fn):
        self._hooks.append(hook_fn)

    def forward(self, x: np.ndarray) -> np.ndarray:
        N, C_in, H, W_in = x.shape
        C_out, _, kH, kW = self.W.shape
        p = kH // 2
        if p > 0:
            x_pad = np.pad(x, ((0,0),(0,0),(p,p),(p,p)))
        else:
            x_pad = x
        H_out = x_pad.shape[2] - kH + 1
        W_out = x_pad.shape[3] - kW + 1
        out = np.zeros((N, C_out, H_out, W_out))
        for n in range(N):
            for co in range(C_out):
                for i in range(H_out):
                    for j in range(W_out):
                        patch = x_pad[n, :, i:i+kH, j:j+kW]
                        out[n, co, i, j] = float(np.sum(patch * self.W[co])) + self.b[co]
        out = np.maximum(0, out)  # ReLU
        for hook_fn in self._hooks:
            hook_fn(out)
        return out

def visualize_feature_map(feature_map: np.ndarray) -> dict:
    # Compute stats over (N, H, W) per channel
    return {
        'mean': feature_map.mean(axis=(0, 2, 3)),
        'std': feature_map.std(axis=(0, 2, 3)),
        'max': feature_map.max(axis=(0, 2, 3)),
        'min': feature_map.min(axis=(0, 2, 3)),
    }
